<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="90" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Let's Talk Tangible Assets</p>
      <p slot="message">Please gather your assets and/or liabilities that can be put up against your mortgage. These are not mandatory but will help expedite your application.</p>
    </message-modal>
    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <b-field label="Primary banking" :addons="false" class="info">
              <b-tooltip label="Please provide us with your main bank account details. (Please enter the balance in digits.)" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-field>
                <b-field class="control" style="flex: 3;">
                  <b-input ref="check1" v-model="bankingInstitution" type="text" icon="university" placeholder="Instutution" expanded required></b-input>
                </b-field>
                <b-field class="control" style="flex: 2;">
                  <b-input ref="check2" type="number" v-model="accountBalance" icon="dollar-sign" placeholder="Balance" required></b-input>
                </b-field>
                <b-field class="control">
                  <b-select ref="check3" icon="piggy-bank" v-model="primaryAccount" placeholder="Account" required>
                    <option value="chequing">Chequing</option>
                    <option value="saving">Saving</option>
                  </b-select>
                </b-field>
              </b-field>
            </b-field>
          </div>
        </div>

        <assets-liabilities></assets-liabilities>

        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <div class="columns">
              <div class="column is-half">
                <b-field label="Do you own real estate?" :addons="false" class="info">
                  <b-tooltip label="Commercial and/or residential" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-field>
                    <b-radio-button class="full-radio" v-model="ownsRealEstate" :native-value="true">
                      <b-icon icon="check-circle"></b-icon>&thinsp;
                      <span>Yes I do</span>
                    </b-radio-button>
                    <b-radio-button class="full-radio" v-model="ownsRealEstate" :native-value="false">
                      <b-icon icon="times-circle"></b-icon>&thinsp;
                      <span>No I don't</span>
                    </b-radio-button>
                  </b-field>
                </b-field>
              </div>
            </div>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <hr>
          </div>
        </div>

        <to-page :next="toProperties" :text="toPropertiesText"></to-page>
      </div>
    </div>
  </div>
</template>

<script>
import assetsLiabilities from "../components/assets-liabilities.vue";
export default {
  beforeRouteLeave(to, from, next) {
    let entries = [];
    for (const key in this.$refs) {
      if (this.$refs.hasOwnProperty(key) && key !== "checkAdd") {
        const ref = this.$refs[key];
        const checked = ref.checkHtml5Validity();
        entries.push(checked);
      }
    }

    if (entries.every(entry => entry === true) || to.path.includes('co-applicant') || to.path.includes('employment')) {
      this.$store.commit("updateForm", {
        name: "AssetsLiabilitiesForm",
        data: this.$store.state.AssetsLiabilitiesForm
      });
      next();
    } else {
      next(false);
      this.$toast.open({
        duration: 2200,
        position: "is-bottom",
        message: `Please fill out the highlighted fields`,
        type: "is-danger"
      });
    }
  },
  data() {
    return {
      page: "Page 6",
      heading: "Your Assets & Liabilities",
      toggled: false
    };
  },
  computed: {
    toProperties() {
      return this.$store.state.AssetsLiabilitiesForm.ownsRealEstate
        ? "/properties"
        : "/signatures";
    },
    toPropertiesText() {
      return this.$store.state.AssetsLiabilitiesForm.ownsRealEstate
        ? "Go to Properties Page"
        : "Sign the Form";
    },
    bankingInstitution: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.bankingInstitution;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.bankingInstitution = val;
      }
    },
    accountBalance: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.accountBalance;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.accountBalance = val;
      }
    },
    primaryAccount: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.primaryAccount;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.primaryAccount = val;
      }
    },
    ownsRealEstate: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.ownsRealEstate;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.ownsRealEstate = val;
      }
    }
  },
  components: {
    assetsLiabilities
  }
};
</script>